import React from 'react';
import logo from '../assets/logo.png';

export default function Hero() {
  return (
    <section className="relative overflow-hidden bg-[#f9f8f6] border-b border-gray-200">

      {/* Faint watermark text */}
      <div
        aria-hidden="true"
        className="absolute inset-0 flex items-center justify-center pointer-events-none select-none"
        style={{ zIndex: 0 }}
      >
        <span
          className="text-[130px] font-black tracking-[16px] uppercase whitespace-nowrap"
          style={{ color: 'rgba(0,0,0,0.028)', fontFamily: 'Playfair Display, serif' }}
        >
          ANIMEMONKEY
        </span>
      </div>

      {/* Content */}
      <div className="relative z-10 flex flex-col items-center justify-center text-center px-6 py-14">

        {/* Logo — big, centered, premium */}
        <img
          src={logo}
          alt="AnimeMonkey"
          className="h-64 md:h-80 lg:h-96 w-auto object-contain mb-2 transition-transform duration-500 hover:scale-[1.02]"
          style={{
            filter: 'drop-shadow(0 20px 60px rgba(0,0,0,0.22))',
            maxWidth: '600px',
          }}
        />

        {/* Tagline */}
        <p
          className="text-sm font-bold tracking-[5px] uppercase mt-1 mb-6"
          style={{ color: '#999', fontFamily: 'Playfair Display, serif' }}
        >
          Anime · Marvel · Mechs · More
        </p>

        {/* CTAs */}
        <div className="flex flex-wrap items-center justify-center gap-3 mb-8">
          <button className="bg-ink text-white px-7 py-3 rounded-lg text-sm font-semibold hover:bg-gray-800 transition-colors">
            Shop Now →
          </button>
          <button className="bg-white text-ink border border-gray-300 px-6 py-3 rounded-lg text-sm font-medium hover:border-ink transition-colors">
            New Arrivals
          </button>
        </div>

        {/* Stats */}
        <div className="flex items-center gap-10">
          {[
            { num: '500+', lbl: 'Products' },
            { num: '40+', lbl: 'Series' },
            { num: '24h', lbl: 'Dispatch' },
            { num: '10k+', lbl: 'Happy Fans' },
          ].map(stat => (
            <div key={stat.lbl} className="text-center">
              <div
                className="text-2xl font-black text-ink leading-none"
                style={{ fontFamily: 'Playfair Display, serif' }}
              >
                {stat.num}
              </div>
              <div className="text-[10px] tracking-[2px] uppercase text-gray-400 mt-1">
                {stat.lbl}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
